class Solution {
    public String reverseStr(String s, int k) {
        char[] a = s.toCharArray();
        for (int i = 0; i &lt; a.length; i += 2 * k) {
            int l = i, r = Math.min(i + k - 1, a.length - 1);
            while (l &lt; r) { char t = a[l]; a[l++] = a[r]; a[r--] = t; }
