class Solution {
    public int[] productExceptSelf(int[] nums) {
        int n = nums.length;
        int[] ans = new int[n];
        int left = 1;
        for (int i = 0; i &lt; n; i++) { ans[i] = left; left *= nums[i]; }
        int right = 1;
        for (int i = n - 1; i &gt;= 0; i--) { ans[i] *= right; right *= nums[i]; }
        return ans;
    }
}

