class MedianFinder {
    PriorityQueue&lt;Integer&gt; lo = new PriorityQueue&lt;&gt;(Collections.reverseOrder());
    PriorityQueue&lt;Integer&gt; hi = new PriorityQueue&lt;&gt;();

    public void addNum(int num) {
        if (lo.isEmpty() || num &lt;= lo.peek()) lo.offer(num); else hi.offer(num);
        if (lo.size() &gt; hi.size() + 1) hi.offer(lo.poll());
        if (hi.size() &gt; lo.size()) lo.offer(hi.poll());
    }

    public double findMedian() {
        if (lo.size() == hi.size()) return ((double)lo.peek() + hi.peek()) / 2.0;
        return lo.peek();
    }
}

class Solution {
    public int[] sortArray(int[] nums) {
        mergeSort(nums, 0, nums.length - 1, new int[nums.length]);
        return nums;
    }
    private void mergeSort(int[] a, int l, int r, int[] tmp) {
        if (l &gt;= r) return;
        int m = l + (r - l) / 2;
        mergeSort(a, l, m, tmp);
        mergeSort(a, m + 1, r, tmp);
        merge(a, l, m, r, tmp);
    }
    private void merge(int[] a, int l, int m, int r, int[] tmp) {
        int i = l, j = m + 1, k = l;
        while (i &lt;= m &amp;&amp; j &lt;= r) tmp[k++] = a[i] &lt;= a[j] ? a[i++] : a[j++];
        while (i &lt;= m) tmp[k++] = a[i++];
        while (j &lt;= r) tmp[k++] = a[j++];
        for (i = l; i &lt;= r; i++) a[i] = tmp[i];
    }
}

class Solution {
    public int[][] spiralMatrixIII(int rows, int cols, int r, int c) {
        int[][] ans = new int[rows * cols][2];
        int idx = 0;
        int[][] dirs = {{0,1},{1,0},{0,-1},{-1,0}};
        int step = 1;
        ans[idx++] = new int[]{r, c};
        while (idx &lt; rows * cols) {
            for (int d = 0; d &lt; 4; d++) {
                for (int s = 0; s &lt; step; s++) {
                    r += dirs[d][0]; c += dirs[d][1];
                    if (0 &lt;= r &amp;&amp; r &lt; rows &amp;&amp; 0 &lt;= c &amp;&amp; c &lt; cols) ans[idx++] = new int[]{r, c};
                }
                if (d == 1 || d == 3) step++;
            }
        }
        return ans;
    }
}

class Solution {
    public int numIslands(char[][] grid) {
        int m = grid.length, n = grid[0].length, count = 0;
        for (int i = 0; i &lt; m; i++)
            for (int j = 0; j &lt; n; j++)
                if (grid[i][j] == '1') { count++; dfs(grid, i, j); }
        return count;
    }
    private void dfs(char[][] g, int r, int c) {
        if (r &lt; 0 || c &lt; 0 || r == g.length || c == g[0].length || g[r][c] != '1') return;
        g[r][c] = '0';
        dfs(g, r+1, c); dfs(g, r-1, c); dfs(g, r, c+1); dfs(g, r, c-1);
    }
}

class Solution {
    public int numEnclaves(int[][] grid) {
        int m = grid.length, n = grid[0].length;
        for (int i = 0; i &lt; m; i++) { dfs(grid, i, 0); dfs(grid, i, n - 1); }
        for (int j = 0; j &lt; n; j++) { dfs(grid, 0, j); dfs(grid, m - 1, j); }
        int ans = 0;
        for (int[] row : grid) for (int x : row) if (x == 1) ans++;
        return ans;
    }
    private void dfs(int[][] g, int r, int c) {
        if (r &lt; 0 || c &lt; 0 || r == g.length || c == g[0].length || g[r][c] == 0) return;
        g[r][c] = 0;
        dfs(g, r+1, c); dfs(g, r-1, c); dfs(g, r, c+1); dfs(g, r, c-1);
    }
}

class Solution {
    public List&lt;List&lt;String&gt;&gt; groupAnagrams(String[] strs) {
