        }
        return new ArrayList&lt;&gt;(map.values());
    }
}

class Solution {
    public String minWindow(String s, String t) {
        int[] need = new int[128];
        for (char c : t.toCharArray()) need[c]++;
        int missing = t.length(), l = 0, bestL = 0, best = Integer.MAX_VALUE;
        for (int r = 0; r &lt; s.length(); r++) {
            if (need[s.charAt(r)]-- &gt; 0) missing--;
            while (missing == 0) {
                if (r - l + 1 &lt; best) { best = r - l + 1; bestL = l; }
                if (++need[s.charAt(l++)] &gt; 0) missing++;
            }
        }
        return best == Integer.MAX_VALUE ? "" : s.substring(bestL, bestL + best);
    }
}

class Solution {
    public List&lt;Integer&gt; findSubstring(String s, String[] words) {
        List&lt;Integer&gt; res = new ArrayList&lt;&gt;();
        if (words.length == 0) return res;
        int w = words[0].length();
        Map&lt;String, Integer&gt; need = new HashMap&lt;&gt;();
        for (String x : words) need.put(x, need.getOrDefault(x, 0) + 1);
        for (int off = 0; off &lt; w; off++) {
            Map&lt;String, Integer&gt; have = new HashMap&lt;&gt;();
            int l = off, count = 0;
            for (int r = off; r + w &lt;= s.length(); r += w) {
                String cur = s.substring(r, r + w);
                if (!need.containsKey(cur)) { have.clear(); count = 0; l = r + w; continue; }
                have.put(cur, have.getOrDefault(cur, 0) + 1);
                count++;
                while (have.get(cur) &gt; need.get(cur)) {
                    String left = s.substring(l, l + w);
                    have.put(left, have.get(left) - 1);
                    l += w; count--;
                }
                if (count == words.length) res.add(l);
            }
        }
        return res;
    }
}

class Solution {
    static class Node { Node[] ch = new Node[26]; String word; }

    public List&lt;String&gt; findWords(char[][] board, String[] words) {
        Node root = new Node();
        for (String w : words) insert(root, w);
        List&lt;String&gt; res = new ArrayList&lt;&gt;();
        for (int i = 0; i &lt; board.length; i++)
            for (int j = 0; j &lt; board[0].length; j++)
                dfs(board, i, j, root, res);
        return res;
    }
    private void insert(Node root, String w) {
        for (char c : w.toCharArray()) {
            int k = c - 'a';
            if (root.ch[k] == null) root.ch[k] = new Node();
            root = root.ch[k];
        }
        root.word = w;
    }
    private void dfs(char[][] b, int r, int c, Node node, List&lt;String&gt; res) {
        if (r &lt; 0 || c &lt; 0 || r == b.length || c == b[0].length || b[r][c] == '#') return;
        char ch = b[r][c];
        Node next = node.ch[ch - 'a'];
        if (next == null) return;
        if (next.word != null) { res.add(next.word); next.word = null; }
        b[r][c] = '#';
        dfs(b, r+1, c, next, res); dfs(b, r-1, c, next, res);
        dfs(b, r, c+1, next, res); dfs(b, r, c-1, next, res);
        b[r][c] = ch;
    }
}

class Solution {
    boolean[][] rows = new boolean[9][9];
    boolean[][] cols = new boolean[9][9];
    boolean[][] boxes = new boolean[9][9];

    public void solveSudoku(char[][] board) {
        for (int r = 0; r &lt; 9; r++) {
            for (int c = 0; c &lt; 9; c++) {
                if (board[r][c] != '.') {
                    int d = board[r][c] - '1';
                    rows[r][d] = cols[c][d] = boxes[(r/3)*3 + c/3][d] = true;
                }
            }
        }
        solve(board, 0, 0);
    }
    private boolean solve(char[][] board, int r, int c) {
        if (r == 9) return true;
        int nr = (c == 8) ? r + 1 : r;
        int nc = (c == 8) ? 0 : c + 1;
        if (board[r][c] != '.') return solve(board, nr, nc);
        int box = (r/3)*3 + c/3;
        for (int d = 0; d &lt; 9; d++) {
            if (rows[r][d] || cols[c][d] || boxes[box][d]) continue;
            board[r][c] = (char)('1' + d);
            rows[r][d] = cols[c][d] = boxes[box][d] = true;
            if (solve(board, nr, nc)) return true;
            board[r][c] = '.';
            rows[r][d] = cols[c][d] = boxes[box][d] = false;
        }
        return false;
    }
}

class Solution {
    public List&lt;String&gt; fullJustify(String[] words, int maxWidth) {
        List&lt;String&gt; result = new ArrayList&lt;&gt;();
        int i = 0;
        while (i &lt; words.length) {
            int lineLen = words[i].length(), j = i + 1;
            while (j &lt; words.length &amp;&amp; lineLen + 1 + words[j].length() &lt;= maxWidth)
                lineLen += 1 + words[j++].length();
            result.add(buildLine(words, i, j, lineLen, maxWidth, j == words.length));
            i = j;
        }
        return result;
    }
    private String buildLine(String[] words, int lo, int hi, int lineLen, int max, boolean last) {
        int gaps = hi - lo - 1;
        StringBuilder sb = new StringBuilder(words[lo]);
        if (gaps == 0 || last) {
            for (int k = lo + 1; k &lt; hi; k++) sb.append(' ').append(words[k]);
            while (sb.length() &lt; max) sb.append(' ');
        } else {
            int totalSpaces = max - lineLen + gaps;
            int each = totalSpaces / gaps, extra = totalSpaces % gaps;
            for (int k = lo + 1; k &lt; hi; k++) {
                int sp = each + (k - lo &lt;= extra ? 1 : 0);
                sb.append(" ".repeat(sp)).append(words[k]);
            }
        }
        return sb.toString();
    }
}

class Solution {
    public int maxProfit(int k, int[] prices) {
        int n = prices.length;
        if (k &gt;= n / 2) {
            int profit = 0;
            for (int i = 1; i &lt; n; i++) profit += Math.max(0, prices[i] - prices[i-1]);
            return profit;
        }
        int[] buy = new int[k + 1], sell = new int[k + 1];
        Arrays.fill(buy, Integer.MIN_VALUE);
        for (int price : prices) {
            for (int j = k; j &gt;= 1; j--) {
                sell[j] = Math.max(sell[j], buy[j] + price);
                buy[j] = Math.max(buy[j], sell[j-1] - price);
            }
        }
        return sell[k];
    }
}

class Solution {
    public int calculateMinimumHP(int[][] dungeon) {
        int m = dungeon.length, n = dungeon[0].length;
        int[][] dp = new int[m + 1][n + 1];
        for (int[] row : dp) Arrays.fill(row, Integer.MAX_VALUE);
        dp[m][n-1] = dp[m-1][n] = 1;
        for (int r = m - 1; r &gt;= 0; r--) {
            for (int c = n - 1; c &gt;= 0; c--) {
                int need = Math.min(dp[r+1][c], dp[r][c+1]) - dungeon[r][c];
                dp[r][c] = Math.max(1, need);
            }
        }
        return dp[0][0];
    }
}

class Solution {
    public int countSubstrings(String s) {
        int count = 0;
        for (int center = 0; center &lt; 2 * s.length() - 1; center++) {
            int l = center / 2, r = l + center % 2;
            while (l &gt;= 0 &amp;&amp; r &lt; s.length() &amp;&amp; s.charAt(l) == s.charAt(r)) {
                count++;
                l--; r++;
            }
        }
        return count;
    }
}

class Solution {
    public int minimumChanges(String s, int k) {
        int n = s.length();
        int[][] cost = new int[n][n];
        for (int i = 0; i &lt; n; i++) {
            for (int j = i + 1; j &lt; n; j++) {
                int len = j - i + 1;
                int best = len;
                for (int d = 1; d * 2 &lt;= len; d++) {
                    if (len % d != 0) continue;
                    int changes = 0;
                    for (int p = 0; p &lt; d; p++) {
                        int lo = i + p, hi = j - p;
                        while (lo &lt; hi) {
                            if (s.charAt(lo) != s.charAt(hi)) changes++;
                            lo += d; hi -= d;
                        }
                    }
                    best = Math.min(best, changes);
                }
                cost[i][j] = best;
            }
        }
        int[][] dp = new int[k + 1][n];
        for (int[] row : dp) Arrays.fill(row, Integer.MAX_VALUE / 2);
        for (int q = 0; q &lt; n; q++) dp[1][q] = cost[0][q];
        for (int p = 2; p &lt;= k; p++) {
            for (int q = 2 * p - 1; q &lt; n; q++) {
                for (int m = 2 * (p - 1) - 1; m &lt; q; m++) {
                    if (dp[p-1][m] &lt; Integer.MAX_VALUE / 2)
                        dp[p][q] = Math.min(dp[p][q], dp[p-1][m] + cost[m+1][q]);
                }
            }
        }
        return dp[k][n-1];
    }
}

class Solution {
    static final int MOD = 1_000_000_007;

    public long countAnagrams(String s) {
        int n = s.length();
        long[] fact = new long[n + 1];
        fact[0] = 1;
        for (int i = 1; i &lt;= n; i++) fact[i] = fact[i-1] * i % MOD;
        long ans = 1;
        for (String word : s.split(" ")) {
            int[] cnt = new int[26];
            for (char c : word.toCharArray()) cnt[c - 'a']++;
            long ways = fact[word.length()];
            for (int x : cnt) ways = ways * modPow(fact[x], MOD - 2) % MOD;
            ans = ans * ways % MOD;
        }
        return ans;
    }
    private long modPow(long base, long exp) {
        long result = 1; base %= MOD;
        while (exp &gt; 0) {
            if ((exp &amp; 1) == 1) result = result * base % MOD;
            base = base * base % MOD;
            exp &gt;&gt;= 1;
        }
        return result;
    }
}

class Solution {
    public String longestCommonPrefix(String[] strs) {
        String prefix = strs[0];
        for (int i = 1; i &lt; strs.length; i++)
            while (strs[i].indexOf(prefix) != 0)
                prefix = prefix.substring(0, prefix.length() - 1);
        return prefix;
    }
}

class Solution {
    private int[] arr;
    private Map&lt;Integer, List&lt;Integer&gt;&gt; positions;
    private Random rand;

    public Solution(int[] arr) {
        this.arr = arr;
        positions = new HashMap&lt;&gt;();
        rand = new Random();
        for (int i = 0; i &lt; arr.length; i++)
            positions.computeIfAbsent(arr[i], k -&gt; new ArrayList&lt;&gt;()).add(i);
    }

    public int query(int left, int right, int threshold) {
        int len = right - left + 1;
        for (int t = 0; t &lt; 20; t++) {
            int candidate = arr[left + rand.nextInt(len)];
            List&lt;Integer&gt; idx = positions.getOrDefault(candidate, List.of());
            int lo = Collections.binarySearch(idx, left);
            if (lo &lt; 0) lo = ~lo;
            int hi = Collections.binarySearch(idx, right + 1);
            if (hi &lt; 0) hi = ~hi;
            if (hi - lo &gt;= threshold) return candidate;
        }
        return -1;
    }
}
